$_MODULE['<{gamifications}prestashop>rewards_info_63b3dbba93a027269de87610d68e9537'] = 'Recompensas são algo que o cliente terá após concluir ou realizar algum tipo de tarefa / desafio.';
$_MODULE['<{gamifications}prestashop>rewards_info_195d14aa24e99d1201795dec20e9370c'] = 'Todas as recompensas (exceto pontos) serão fornecidas em forma de voucher.';
$_MODULE['<{gamifications}prestashop>rewards_info_e0bf2636d2014cb5414a1a2bf266d8f8'] = 'As recompensas podem depois ser atribuídas a qualquer atividade ou troca de pontos!';
$_MODULE['<{gamifications}prestashop>rewards_info_533e595014491e6b10fdb687a4d050f9'] = 'Como uso as recompensas?';
$_MODULE['<{gamifications}prestashop>rewards_info_b0bdbc1cb28329e0c163f7ca37376626'] = 'Crie uma recompensa e atribua-a à atividade. Pode usar uma recompensa única em várias atividades.';
$_MODULE['<{gamifications}prestashop>shopping_points_info_a5dca02d9d92a5ab485adb930cb4e0e6'] = 'O que são Pontos de Compra?';
$_MODULE['<{gamifications}prestashop>shopping_points_info_6530554ef142af3ac9cdf578ff8dbdf2'] = 'Os Pontos de Compra permitem que os seus clientes ganhem pontos e os troquem em recompensas da Point Exchange.';
$_MODULE['<{gamifications}prestashop>shopping_points_info_850f718a4d0baa915b27a10acc4229a8'] = 'Os pontos são calculados na moeda padrão';
$_MODULE['<{gamifications}prestashop>shopping_points_info_2fc6ee5af4cce674d4907896d65fc3dc'] = 'Como usar os Pontos de Compra?';
$_MODULE['<{gamifications}prestashop>shopping_points_info_2b5aa2150ae4f52131a0ac91dcc24ebf'] = '1. Defina quantos pontos o cliente receberá após gastar 1 unidade de dinheiro. Por exemplo. 2 pontos por 1 gasto em EUR ou 10 pontos por 1 USD gasto.';
$_MODULE['<{gamifications}prestashop>shopping_points_info_44d313959e0137252a24e0a91640564f'] = '2. Defina os estados da ordem após os quais o cliente será recompensado com pontos.';
$_MODULE['<{gamifications}prestashop>shopping_points_info_5968015899b05112b3e0278862adaeac'] = '3. Escolha se deseja incluir o preço de envio ao calcular pontos.';
$_MODULE['<{gamifications}prestashop>shopping_points_info_029f5c90840151adaad0ea65af34fa20'] = '4. Ativar atividade em Preferências. É assim! Os clientes agora podem acessar seu URL de referência exclusivo na página da conta. ';
$_MODULE['<{gamifications}prestashop>daily_rewards_info_763e79a8136ea66fac785f11e03a7c81'] = 'O que são as recompensas diárias?';
$_MODULE['<{gamifications}prestashop>daily_rewards_info_4b6b9ba504bcc268edabe2011a3efb38'] = 'As recompensas diárias permitem que você, como comerciante, atraia mais clientes para a sua loja todos os dias, dando-lhes recompensas aleatórias';
$_MODULE['<{gamifications}prestashop>daily_rewards_info_bc0e36e7abb36da80d8306909c3db9cf'] = 'Tudo o que o cliente precisa fazer é visitar a sua loja e reivindicar a sua recompensa diária! A recompensa é geralmente uma quantidade aleatória de pontos, mas também pode ser desconto, frete grátis ou presente';
$_MODULE['<{gamifications}prestashop>daily_rewards_info_788c01a64324010d793e59d45a4a8bef'] = 'Como as recompensas diárias aumentam as vendas?';
$_MODULE['<{gamifications}prestashop>daily_rewards_info_5663a925cc13c9de691f07ca879658b7'] = 'Os clientes podem converter os pontos em frete grátis ou descontos, o que os encoraja a fazer pedidos e a visitar a sua loja com mais frequência!';
$_MODULE['<{gamifications}prestashop>points_exchange_info_2359b9370b62bf723cfc4a3d7a72111b'] = 'O que é a Troca de Pontos? ';
$_MODULE['<{gamifications}prestashop>points_exchange_info_220ae322355abd0ebf399fe09c5183a6'] = 'A troca de pontos é usada no Front Office para permitir que os clientes troquem pontos em recompensas.';
$_MODULE['<{gamifications}prestashop>points_exchange_info_0066c957c4705384889c6b6f557df962'] = 'Como usar a Troca de Pontos?';
$_MODULE['<{gamifications}prestashop>points_exchange_info_a473a091b2bd039e7a1e7a75de9ed048'] = 'Tem que relacionar a quantidade fixa de pontos com recompensa, se trata disso!';
$_MODULE['<{gamifications}prestashop>points_exchange_info_1dc988fb4c10d996829e387e8396c6b6'] = 'Por exemplo. Digamos que o cliente tenha 135 pontos e haja uma recompensa \"Envio grátis\", que exige 100 pontos para receber.';
$_MODULE['<{gamifications}prestashop>points_exchange_info_e48c121603cc801cd97de7b85cbbc2db'] = 'Isso significa que o cliente pode receber \"Envio grátis\" por 100 pontos e ainda ter 35 pontos restantes.';
